#!/usr/bin/env bash
set -Eeuo pipefail

# Section 18 exact audited-results commit.
#
# This automation is independent of files 36, 37, and 38. It does not call
# them, does not recurse through configs/docs/report directories, and does not
# rerun experiments. It stages only:
#   1. exact structured result files named by the newest PASS audit manifest;
#   2. exact PASS audit evidence;
#   3. a small, explicit Section 18 reproducibility set; and
#   4. release evidence generated by this automation.

EXPECTED_BRANCH="feature/18-main-experiment-matrix"
EVIDENCE_DIR="reports/evidence/section18"
LATEST_AUDIT="$EVIDENCE_DIR/section18_full_matrix_audit_latest.txt"
COMMIT_MESSAGE="Add audited Section 18 experiment results"
MAX_FILES=64
MAX_FILE_BYTES=$((50 * 1024 * 1024))
MAX_TOTAL_BYTES=$((250 * 1024 * 1024))
STAMP="$(date -u +%Y%m%dT%H%M%SZ)"
COMMIT_MANIFEST="$EVIDENCE_DIR/section18_exact_commit_manifest_${STAMP}.csv"
RELEASE_SUMMARY="$EVIDENCE_DIR/section18_exact_result_release_${STAMP}.txt"
DUPLICATE_REVIEW="$EVIDENCE_DIR/section18_duplicate_identity_review_${STAMP}.txt"
CANDIDATE_NUL="$(mktemp)"
CANDIDATE_TEXT="$(mktemp)"

cleanup() {
  rm -f "$CANDIDATE_NUL" "$CANDIDATE_TEXT"
}
trap cleanup EXIT

fail() {
  echo "ERROR: $*" >&2
  exit 1
}

header() {
  printf '\n%s\n' "======================================================================"
  printf '%s\n' "$1"
  printf '%s\n' "======================================================================"
}

REPO_ROOT="$(git rev-parse --show-toplevel 2>/dev/null || true)"
[[ -n "$REPO_ROOT" ]] || fail "Run this automation from inside the budgetmem-r Git repository."
cd "$REPO_ROOT"

BRANCH="$(git branch --show-current)"
[[ "$BRANCH" == "$EXPECTED_BRANCH" ]] || \
  fail "Expected branch '$EXPECTED_BRANCH', found '$BRANCH'."

if ! git diff --cached --quiet; then
  fail "The Git index already contains staged changes. Unstage them before running this automation."
fi

[[ -f "$LATEST_AUDIT" ]] || fail "Missing final audit: $LATEST_AUDIT"
grep -Fq "FINAL DECISION: SECTION 18 FULL MATRIX AUDIT PASSED" "$LATEST_AUDIT" || \
  fail "The latest Section 18 audit does not contain the required PASS decision."

mapfile -t AUDIT_PATHS < <(
  python - "$REPO_ROOT" "$EVIDENCE_DIR" <<'PY'
from __future__ import annotations

import json
import sys
from pathlib import Path

root = Path(sys.argv[1]).resolve()
evidence = (root / sys.argv[2]).resolve()

candidates: list[tuple[float, Path, dict[str, object]]] = []
for path in evidence.glob("section18_full_matrix_audit_*.json"):
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        continue
    if data.get("decision") == "PASS" and not data.get("blocking_reasons"):
        candidates.append((path.stat().st_mtime, path, data))

if not candidates:
    raise SystemExit("ERROR: No timestamped PASS Section 18 audit JSON was found.")

_, audit_json, data = max(candidates, key=lambda item: item[0])
manifest_value = str(data.get("manifest") or "").strip()
if not manifest_value:
    raise SystemExit("ERROR: PASS audit JSON does not identify its result-file manifest.")
manifest = Path(manifest_value)
if not manifest.is_absolute():
    manifest = root / manifest
manifest = manifest.resolve()
if not manifest.is_file():
    raise SystemExit(f"ERROR: Audit manifest does not exist: {manifest}")

audit_txt = audit_json.with_suffix(".txt")
if not audit_txt.is_file():
    raise SystemExit(f"ERROR: Matching timestamped audit report does not exist: {audit_txt}")

for path in (audit_json, manifest, audit_txt):
    try:
        print(path.relative_to(root).as_posix())
    except ValueError as exc:
        raise SystemExit(f"ERROR: Audit evidence is outside the repository: {path}") from exc
PY
)

(( ${#AUDIT_PATHS[@]} == 3 )) || fail "Could not resolve PASS audit evidence."
AUDIT_JSON="${AUDIT_PATHS[0]}"
RESULT_MANIFEST="${AUDIT_PATHS[1]}"
TIMESTAMPED_AUDIT="${AUDIT_PATHS[2]}"

header "VERIFY PASSED SECTION 18 AUDIT"
echo "Repository: $REPO_ROOT"
echo "Branch: $BRANCH"
echo "Latest audit: $LATEST_AUDIT"
echo "Audit JSON: $AUDIT_JSON"
echo "Result manifest: $RESULT_MANIFEST"
echo "Timestamped audit: $TIMESTAMPED_AUDIT"
echo "Selection mode: exact PASS-manifest rows plus explicit durable files"
echo "Recursive configs/docs scan: NO"
echo "Recursive report scan: NO"
echo "Full matrix rerun: NO"

python - "$AUDIT_JSON" "$RESULT_MANIFEST" <<'PY'
from __future__ import annotations

import csv
import json
import sys
from pathlib import Path

audit_path = Path(sys.argv[1])
manifest_path = Path(sys.argv[2])
audit = json.loads(audit_path.read_text(encoding="utf-8"))
if audit.get("decision") != "PASS" or audit.get("blocking_reasons"):
    raise SystemExit("ERROR: Audit JSON is not eligible for release.")
with manifest_path.open("r", encoding="utf-8-sig", newline="") as fh:
    rows = list(csv.DictReader(fh))
expected = audit.get("result_file_count")
if isinstance(expected, int) and len(rows) != expected:
    raise SystemExit(
        f"ERROR: Audit reports {expected} result files, but its manifest contains {len(rows)} rows."
    )
if not rows:
    raise SystemExit("ERROR: The PASS audit manifest is empty.")
print("Audit JSON decision: PASS")
print(f"Audited result files: {len(rows)}")
print(f"Parsed result rows: {audit.get('parsed_result_rows', 'unknown')}")
print(f"Observed experiment identities: {audit.get('observed_identity_rows', 'unknown')}")
print(f"Explicit OOM rows: {audit.get('oom_rows', 0)}")
PY

header "BUILD EXACT AUDITED RESULT BUNDLE"

python - \
  "$REPO_ROOT" \
  "$AUDIT_JSON" \
  "$RESULT_MANIFEST" \
  "$TIMESTAMPED_AUDIT" \
  "$LATEST_AUDIT" \
  "$COMMIT_MANIFEST" \
  "$RELEASE_SUMMARY" \
  "$DUPLICATE_REVIEW" \
  "$CANDIDATE_NUL" \
  "$CANDIDATE_TEXT" \
  "$MAX_FILES" \
  "$MAX_FILE_BYTES" \
  "$MAX_TOTAL_BYTES" <<'PY'
from __future__ import annotations

import csv
import hashlib
import json
import os
import sys
from collections import Counter, defaultdict
from pathlib import Path
from typing import Any

root = Path(sys.argv[1]).resolve()
audit_json = (root / sys.argv[2]).resolve()
result_manifest = (root / sys.argv[3]).resolve()
timestamped_audit = (root / sys.argv[4]).resolve()
latest_audit = (root / sys.argv[5]).resolve()
commit_manifest = (root / sys.argv[6]).resolve()
release_summary = (root / sys.argv[7]).resolve()
duplicate_review = (root / sys.argv[8]).resolve()
candidate_nul = Path(sys.argv[9]).resolve()
candidate_text = Path(sys.argv[10]).resolve()
max_files = int(sys.argv[11])
max_file_bytes = int(sys.argv[12])
max_total_bytes = int(sys.argv[13])

with audit_json.open("r", encoding="utf-8") as fh:
    audit = json.load(fh)
if audit.get("decision") != "PASS" or audit.get("blocking_reasons"):
    raise SystemExit("ERROR: Audit evidence is not eligible for release.")

allowed_result_suffixes = {".csv", ".json", ".jsonl", ".ndjson", ".parquet"}
forbidden_suffixes = {".pt", ".pth", ".ckpt", ".bin", ".npy", ".npz", ".pkl", ".pickle", ".log"}
forbidden_parts = {
    ".git", ".venv", "__pycache__", "backups", "backup", "checkpoints",
    "checkpoint", "fixtures", "fixture", "smoke", "tmp", "cache", "raw",
}


def normalize_rel(value: str) -> Path:
    value = value.strip().replace("\\", "/")
    if not value:
        raise SystemExit("ERROR: The audit manifest contains a blank path.")
    path = Path(value)
    resolved = path.resolve() if path.is_absolute() else (root / path).resolve()
    try:
        return resolved.relative_to(root)
    except ValueError as exc:
        raise SystemExit(f"ERROR: Manifest path is outside the repository: {value}") from exc


def verify_file(rel: Path, *, result_file: bool = False) -> None:
    path = (root / rel).resolve()
    try:
        path.relative_to(root)
    except ValueError as exc:
        raise SystemExit(f"ERROR: Path escapes the repository: {rel}") from exc
    if not path.is_file():
        raise SystemExit(f"ERROR: Required file does not exist: {rel}")
    lower_parts = {part.lower() for part in rel.parts}
    if lower_parts & forbidden_parts:
        raise SystemExit(f"ERROR: Forbidden runtime path entered the release bundle: {rel}")
    if path.suffix.lower() in forbidden_suffixes:
        raise SystemExit(f"ERROR: Forbidden file type entered the release bundle: {rel}")
    if result_file and path.suffix.lower() not in allowed_result_suffixes:
        raise SystemExit(f"ERROR: Unsupported result-file type in audit manifest: {rel}")


# Exact result files: every row of the PASS audit manifest, and nothing else
# discovered by directory traversal.
manifest_result_paths: list[Path] = []
manifest_hash_mismatches: list[str] = []
with result_manifest.open("r", encoding="utf-8-sig", newline="") as fh:
    reader = csv.DictReader(fh)
    fields = [name for name in (reader.fieldnames or []) if name]
    path_field = next(
        (name for name in fields if name.strip().lower() in {
            "path", "file", "filepath", "file_path", "relative_path", "result_path"
        }),
        None,
    )
    if path_field is None:
        raise SystemExit("ERROR: Audit manifest has no recognized path column.")
    sha_field = next((name for name in fields if name.strip().lower() == "sha256"), None)
    for row in reader:
        rel = normalize_rel(str(row.get(path_field, "")))
        verify_file(rel, result_file=True)
        # The audit itself searched multiple roots. Permit exact files from those
        # roots, but do not recurse into any of them here.
        allowed_prefixes = (
            "reports/tables/section18/",
            "reports/section18/",
            "outputs/section18/",
            "results/section18/",
            "artifacts/section18/",
        )
        rel_text = rel.as_posix().lower()
        if not (
            rel_text.startswith(allowed_prefixes)
            or (rel_text.startswith("reports/tables/") and "section18" in rel.name.lower())
        ):
            raise SystemExit(f"ERROR: Unexpected result location in PASS manifest: {rel}")
        if sha_field:
            expected_sha = str(row.get(sha_field, "")).strip().lower()
            if expected_sha:
                observed_sha = hashlib.sha256((root / rel).read_bytes()).hexdigest()
                if observed_sha != expected_sha:
                    manifest_hash_mismatches.append(rel.as_posix())
        manifest_result_paths.append(rel)

if manifest_hash_mismatches:
    raise SystemExit(
        "ERROR: Result files changed after the PASS audit: " + ", ".join(manifest_hash_mismatches)
    )
manifest_result_paths = sorted(set(manifest_result_paths))
expected_count = audit.get("result_file_count")
if isinstance(expected_count, int) and len(manifest_result_paths) != expected_count:
    raise SystemExit(
        f"ERROR: PASS audit expected {expected_count} unique result files; "
        f"resolved {len(manifest_result_paths)}."
    )

# Small explicit durable set. There is deliberately no configs/ or docs/ scan.
explicit_paths = [
    Path("21_section18_main_experiment_matrix.sh"),
    Path("33_section18_full_matrix_audit.sh"),
    Path("39_section18_exact_audited_results_commit.sh"),
    Path("40_section18_ignored_artifact_repair_and_commit.sh"),
    Path("scripts/run_section18.py"),
    Path("scripts/data/prepare_bgl.py"),
    Path("src/budgetmem/data/bgl.py"),
    Path("src/budgetmem/data/__init__.py"),
    Path("tests/test_section18_release_gate.py"),
    Path("reports/evidence/section18/section18_summary.txt"),
    Path("reports/evidence/section18/section18_runner_release_gate_latest.txt"),
    Path("reports/evidence/section18/section18_runner_readiness_latest.txt"),
    audit_json.relative_to(root),
    result_manifest.relative_to(root),
    timestamped_audit.relative_to(root),
    latest_audit.relative_to(root),
]

candidates: set[Path] = set(manifest_result_paths)
for rel in explicit_paths:
    path = root / rel
    if path.is_file():
        verify_file(rel)
        candidates.add(rel)

# Record the audit's duplicate warning without pretending that it disappeared.
duplicate_identities = audit.get("duplicate_identities") or {}
warnings = [str(item) for item in (audit.get("warnings") or [])]
duplicate_warning_lines = [item for item in warnings if "duplicate" in item.lower()]
counts = Counter()
for value in duplicate_identities.values():
    try:
        counts[int(value)] += 1
    except (TypeError, ValueError):
        continue

duplicate_review.parent.mkdir(parents=True, exist_ok=True)
duplicate_review.write_text(
    "\n".join([
        "Section 18 Duplicate-Identity Review",
        "",
        f"Audit JSON: {audit_json.relative_to(root).as_posix()}",
        f"Audit decision: {audit.get('decision')}",
        f"Parsed result rows: {audit.get('parsed_result_rows', 'unknown')}",
        f"Observed unique experiment identities: {audit.get('observed_identity_rows', 'unknown')}",
        f"Duplicate identities retained in audit JSON sample: {len(duplicate_identities)}",
        f"Audited structured result files: {len(manifest_result_paths)}",
        "",
        "Audit warning:",
        *([f"- {line}" for line in duplicate_warning_lines] or ["- None"]),
        "",
        "Observed multiplicities in the audit JSON sample:",
        *([f"- multiplicity {mult}: {count} sampled identities" for mult, count in sorted(counts.items())] or ["- Not recorded"]),
        "",
        "Release treatment:",
        "- The substantive audit classified duplicate identities as non-blocking.",
        "- The exact audit manifest and audit JSON are retained for traceability.",
        "- No recursive directory expansion is used by this release automation.",
        "- No result row is altered, deduplicated, or rewritten during release.",
        "- Duplicate identities remain a documented analytical caveat for downstream tables.",
        "",
        "REVIEW DECISION: ACCEPT AUDIT-PASSED RESULTS WITH DUPLICATE CAVEAT RECORDED",
        "",
    ]),
    encoding="utf-8",
)

# Create release records before staging.
ordered_candidates = sorted(candidates)
if len(ordered_candidates) + 3 > max_files:
    raise SystemExit(
        f"ERROR: Exact audited bundle would contain {len(ordered_candidates) + 3} files, "
        f"exceeding the safety limit of {max_files}."
    )

records: list[dict[str, Any]] = []
total_bytes = 0
for rel in ordered_candidates:
    path = root / rel
    size = path.stat().st_size
    if size > max_file_bytes:
        raise SystemExit(f"ERROR: File exceeds per-file limit: {rel} ({size} bytes)")
    total_bytes += size
    if total_bytes > max_total_bytes:
        raise SystemExit(f"ERROR: Bundle exceeds total byte limit: {total_bytes}")
    records.append({
        "path": rel.as_posix(),
        "bytes": size,
        "sha256": hashlib.sha256(path.read_bytes()).hexdigest(),
    })

commit_manifest.parent.mkdir(parents=True, exist_ok=True)
with commit_manifest.open("w", encoding="utf-8", newline="") as fh:
    writer = csv.DictWriter(fh, fieldnames=["path", "bytes", "sha256"])
    writer.writeheader()
    writer.writerows(records)

release_summary.write_text(
    "\n".join([
        "Section 18 Exact Audited Result Release",
        "",
        "Audit decision: PASS",
        f"Audit JSON: {audit_json.relative_to(root).as_posix()}",
        f"Audit report: {timestamped_audit.relative_to(root).as_posix()}",
        f"Result-file manifest: {result_manifest.relative_to(root).as_posix()}",
        f"Exact audited result files selected: {len(manifest_result_paths)}",
        f"Explicit durable/evidence files selected: {len(ordered_candidates) - len(manifest_result_paths)}",
        f"Controlled files before release-evidence insertion: {len(ordered_candidates)}",
        f"Controlled source bytes: {total_bytes}",
        "Recursive configs/docs scan used: NO",
        "Recursive report scan used: NO",
        "Per-cell directory expansion used: NO",
        "Result rows rewritten: NO",
        "Full experiment matrix rerun: NO",
        "",
        "FINAL DECISION: SECTION 18 EXACT AUDITED RESULT BUNDLE APPROVED FOR COMMIT",
        "",
    ]),
    encoding="utf-8",
)

final_paths = ordered_candidates + [
    commit_manifest.relative_to(root),
    release_summary.relative_to(root),
    duplicate_review.relative_to(root),
]

with candidate_nul.open("wb") as fh:
    for rel in final_paths:
        fh.write(os.fsencode(rel.as_posix()))
        fh.write(b"\0")
with candidate_text.open("w", encoding="utf-8") as fh:
    for rel in final_paths:
        fh.write(rel.as_posix() + "\n")

print(f"Exact audited result files: {len(manifest_result_paths)}")
print(f"Explicit durable/evidence files: {len(ordered_candidates) - len(manifest_result_paths)}")
print(f"Final controlled files to stage: {len(final_paths)}")
print(f"Controlled source bytes: {total_bytes}")
print("Recursive configs/docs scan: NO")
print("Recursive report scan: NO")
print(f"Commit manifest: {commit_manifest.relative_to(root)}")
print(f"Release summary: {release_summary.relative_to(root)}")
print(f"Duplicate review: {duplicate_review.relative_to(root)}")
PY

[[ -s "$CANDIDATE_NUL" ]] || fail "The exact audited candidate list is empty."
CANDIDATE_COUNT="$(wc -l < "$CANDIDATE_TEXT" | tr -d ' ')"
(( CANDIDATE_COUNT <= MAX_FILES )) || fail "Candidate list exceeds the $MAX_FILES-file safety limit."

header "REVIEW EXACT CONTROLLED FILE LIST"
cat "$CANDIDATE_TEXT"
echo "Exact controlled candidate count: $CANDIDATE_COUNT"

header "STAGE EXACT CONTROLLED FILES"
while IFS= read -r path; do
  [[ -n "$path" ]] || continue
  if git check-ignore -q -- "$path"; then
    echo "Force-adding exact audit-approved ignored file: $path"
    git add -f -- "$path"
  else
    git add -- "$path"
  fi
done < "$CANDIDATE_TEXT"

mapfile -d '' -t STAGED_FILES < <(git diff --cached --name-only -z)
(( ${#STAGED_FILES[@]} > 0 )) || fail "No approved Section 18 artifacts were staged."

restore_index_and_fail() {
  if (( ${#STAGED_FILES[@]} > 0 )); then
    git restore --staged -- "${STAGED_FILES[@]}" >/dev/null 2>&1 || true
  fi
  fail "$1"
}

(( ${#STAGED_FILES[@]} <= MAX_FILES )) || \
  restore_index_and_fail "Staged file count exceeds the $MAX_FILES-file safety limit; index restored."

set +e
python - "$CANDIDATE_TEXT" "${STAGED_FILES[@]}" <<'PY'
from __future__ import annotations

import sys
from pathlib import Path

allowed = {
    line.strip()
    for line in Path(sys.argv[1]).read_text(encoding="utf-8").splitlines()
    if line.strip()
}
staged = {Path(value).as_posix() for value in sys.argv[2:]}
unexpected = sorted(staged - allowed)
if unexpected:
    print("ERROR: Unexpected staged paths:", file=sys.stderr)
    for path in unexpected:
        print(f"  - {path}", file=sys.stderr)
    raise SystemExit(1)
print(f"Exact staged-path boundary: PASS ({len(staged)} files)")
PY
BOUNDARY_STATUS=$?
set -e
(( BOUNDARY_STATUS == 0 )) || restore_index_and_fail "Unexpected paths were staged; index restored."

CHECK_PATHS=()
for path in "${STAGED_FILES[@]}"; do
  case "$path" in
    *.sh|*.py|*.yaml|*.yml|*.toml|*.md)
      CHECK_PATHS+=("$path")
      ;;
  esac
done
if (( ${#CHECK_PATHS[@]} > 0 )); then
  git diff --cached --check -- "${CHECK_PATHS[@]}" || \
    restore_index_and_fail "Whitespace validation failed for maintained files; index restored."
fi

echo "Staged files: ${#STAGED_FILES[@]}"
printf '  %s\n' "${STAGED_FILES[@]}"

header "COMMIT AND PUSH EXACT AUDITED SECTION 18 RESULTS"
git commit -m "$COMMIT_MESSAGE"
COMMIT_HASH="$(git rev-parse HEAD)"
git push -u origin "$BRANCH"

REMAINING_COUNT="$(git status --porcelain=v1 --untracked-files=all | wc -l | tr -d ' ')"

header "SECTION 18 EXACT AUDITED RESULT RELEASE COMPLETED"
echo "FINAL DECISION: SECTION 18 EXACT AUDITED RESULTS COMMITTED AND PUSHED"
echo "Commit: $COMMIT_HASH"
echo "Branch: $BRANCH"
echo "Full matrix rerun: NO"
echo "Recursive configs/docs scan: NO"
echo "Recursive report scan: NO"
echo "Remaining uncommitted/untracked paths: $REMAINING_COUNT"
echo "Commit manifest: $COMMIT_MANIFEST"
echo "Release summary: $RELEASE_SUMMARY"
echo "Duplicate review: $DUPLICATE_REVIEW"
